  output: isExport ? "export" : undefined,
  ...(!isExport && {
    async rewrites() {
      return [
        {
          source: "/api/:path*",
          destination: `${process.env.API_BACKEND_URL || "http://localhost:8080"}/api/:path*`,
        },
        {
          source: "/auth/:path*",
          destination: `${process.env.API_BACKEND_URL || "http://localhost:8080"}/auth/:path*`,
        },
      ];
    },
  }),
};

export default nextConfig;

